    }

    updateDisplay();
  }

  function updateDisplay() {
    let html = '';
    for (let i = 0; i < array.length; i++) {
      if (i >= low && i <= high) {
        html += `<span class="box active">${array[i]}</span>`;
      } else {
        html += `<span class="box">${array[i]}</span>`;
      }
    }
    document.getElementById('arrayDisplay').innerHTML = html;

    if (mid !== undefined) {
      let midElements = document.querySelectorAll('.box');
      midElements[mid].classList.add('mid');
      setTimeout(() => midElements[mid].classList.remove('mid'), 1000);
    }
  }
</script>

</body>
</html>
